const TODAY = new Date();
const BRL = v => `R$ ${Number(v).toLocaleString('pt-BR',{minimumFractionDigits:2,maximumFractionDigits:2})}`;
const parseDate = s => {
  if (!s || typeof s !== 'string') return null;
  const p = s.match(/^(\d{2})\/(\d{2})\/(\d{4})$/);
  return p ? new Date(+p[3], +p[2]-1, +p[1]) : null;
};
const ym = dt => { const d = parseDate(dt); if (!d) return null; return `${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,'0')}`; };
const ymLabel = s => { if (!s) return ''; const [y,m] = s.split('-'); const mn=['Jan','Fev','Mar','Abr','Mai','Jun','Jul','Ago','Set','Out','Nov','Dez']; return `${mn[+m-1]}/${y.slice(2)}`; };
const countByMonth = arr => {
  const m = {};
  arr.forEach(r => { const k = ym(r.data); if (k) m[k] = (m[k]||0)+1; });
  return Object.entries(m).sort().map(([k,v]) => ({ mes: ymLabel(k), count: v }));
};
const valorByMonth = (arr) => {
  const m = {};
  arr.forEach(r => { const k = ym(r.data); if (k) m[k] = (m[k]||0)+(r.valor||0); });
  return Object.entries(m).sort().map(([k,v]) => ({ mes: ymLabel(k), valor: +v.toFixed(2), key: k }));
};
const valorByYear = (arr) => {
  const m = {};
  arr.forEach(r => { const d = parseDate(r.data); if (d) { const y = d.getFullYear(); m[y] = (m[y]||0)+(r.valor||0); } });
  return Object.entries(m).sort().map(([k,v]) => ({ ano: k, valor: +v.toFixed(2) }));
};
const topN = (arr, key, n=7) => {
  const m = {};
  arr.forEach(r => { const v = (r[key]||'').trim().slice(0,45); if (v) m[v] = (m[v]||0)+1; });
  return Object.entries(m).sort((a,b)=>b[1]-a[1]).slice(0,n).map(([name,value])=>({name,value}));
};
const adjStatus2026 = sit => {
  if (!sit) return 'Sem info';
  const s = sit.toUpperCase().trim();
  if (s.includes('REPROVADO')) return 'Reprovado';
  if (s.includes('APROVADO')) return 'Aprovado';
  if (s.includes('INCONCLUSIVO')) return 'Inconclusivo';
  return sit.trim();
};
const STATUS_COLORS_2026 = {'Aprovado':'#16a34a','Reprovado':'#dc2626','Inconclusivo':'#d97706','Sem info':'#9ca3af'};
const CC = ["#2563eb","#d97706","#16a34a","#dc2626","#7c3aed","#db2777","#0891b2","#ea580c","#0d9488"];

const TTip = ({active,payload,label}) => {
  if (!active||!payload?.length) return null;
  return (
    <div className="bg-white border border-gray-200 rounded-lg p-3 text-sm shadow-lg">
      <p className="font-bold text-gray-800 mb-1">{label}</p>
      {payload.map((p,i)=><div key={i} className="text-gray-600">{p.name||'Total'}: <span className="font-bold text-gray-900">{p.dataKey==='valor'?BRL(p.value):p.value}</span></div>)}
    </div>
  );
};
const KPI = ({label,value,color='text-blue-600',sub,bg='bg-blue-50',border='border-blue-100'}) => (
  <div className={`${bg} rounded-xl p-4 border ${border}`}>
    <div className="text-xs text-gray-500 mb-1">{label}</div>
    <div className={`text-2xl font-bold ${color}`}>{value}</div>
    {sub && <div className="text-xs text-gray-400 mt-1">{sub}</div>}
  </div>
);
const Pill = ({text,color}) => (
  <span style={{background:color+'18',color,border:`1px solid ${color}33`}} className="px-2 py-0.5 rounded-full text-xs font-medium whitespace-nowrap">{text}</span>
);
const MiniBar = ({data,color,height=180,dataKey='count'}) => (
  <ResponsiveContainer width="100%" height={height}>
    <BarChart data={data} margin={{left:-10,right:4,top:4,bottom:0}}>
      <CartesianGrid strokeDasharray="3 3" stroke="#f0f0f0"/>
      <XAxis dataKey="mes" tick={{fill:'#9ca3af',fontSize:9}} angle={-45} textAnchor="end" height={36}/>
      <YAxis tick={{fill:'#9ca3af',fontSize:10}}/>
      <Tooltip content={<TTip/>}/>
      <Bar dataKey={dataKey} name={dataKey==='valor'?'Valor':'Qtd'} fill={color} radius={[3,3,0,0]}/>
    </BarChart>
  </ResponsiveContainer>
);
const MiniPie = ({data}) => (
  <ResponsiveContainer width="100%" height={150}>
    <PieChart>
      <Pie data={data} dataKey="value" nameKey="name" cx="50%" cy="50%" outerRadius={55}
        label={({percent})=>`${(percent*100).toFixed(0)}%`} labelLine={false}>
        {data.map((_,i)=><Cell key={i} fill={CC[i%CC.length]}/>)}
      </Pie>
      <Tooltip/>
    </PieChart>
  </ResponsiveContainer>
);

function SMView({SM_DIA, SM_FILIAL}) {
  const smMonths = useMemo(()=>[...new Set([...SM_DIA,...SM_FILIAL].map(r=>ym(r.data)).filter(Boolean))].sort(),[SM_DIA,SM_FILIAL]);
  const [selMonth, setSelMonth] = useState('');
  const [view, setView] = useState("quantidade");
  useEffect(()=>{ if(smMonths.length && !selMonth) setSelMonth(smMonths[smMonths.length-1]); },[smMonths]);
  const chartData = useMemo(() => {
    if(!selMonth) return [];
    const dMap = Object.fromEntries(SM_DIA.map(r => { const [dd,mm,yy]=r.data.split('/'); return [`${yy}-${mm}-${dd}`,r]; }));
    const fMap = Object.fromEntries(SM_FILIAL.map(r => { const [dd,mm,yy]=r.data.split('/'); return [`${yy}-${mm}-${dd}`,r]; }));
    const [y,m] = selMonth.split("-");
    const days = new Date(+y,+m,0).getDate();
    return Array.from({length:days},(_,i) => {
      const dd = String(i+1).padStart(2,"0");
      const key = `${y}-${m}-${dd}`;
      const dia = dMap[key]; const fil = fMap[key];
      return { label:`${dd}/${m}`, diaQtd:dia?.quantidade??null, diaLib:dia?.liberacao??null, filQtd:fil?.quantidade??null, filLib:fil?.liberacao??null };
    });
  }, [selMonth,SM_DIA,SM_FILIAL]);
  const stats = useMemo(() => {
    const sum = (arr,k) => arr.reduce((a,r)=>a+(Number(r[k])||0),0);
    const dd = chartData.filter(r=>r.diaQtd!==null);
    const ff = chartData.filter(r=>r.filQtd!==null);
    return { diaQtd:sum(dd,'diaQtd'), diaLib:sum(dd,'diaLib'), filQtd:sum(ff,'filQtd'), filLib:sum(ff,'filLib') };
  }, [chartData]);
  const showQ = view==='quantidade'||view==='ambos';
  const showL = view==='liberacao'||view==='ambos';
  return (
    <div>
      <div className="flex flex-wrap gap-2 mb-4 items-center">
        <div className="flex gap-1.5 flex-wrap">
          {smMonths.map(m=>(
            <button key={m} onClick={()=>setSelMonth(m)}
              className={`px-2.5 py-1 rounded-lg text-xs font-medium border transition-all ${selMonth===m?'bg-blue-600 text-white border-blue-600':'bg-white text-gray-600 border-gray-200 hover:border-blue-300'}`}>
              {ymLabel(m)}
            </button>
          ))}
        </div>
        <div className="flex gap-1.5 ml-auto">
          {[['quantidade','Qtd'],['liberacao','Lib'],['ambos','Ambos']].map(([v,l])=>(
            <button key={v} onClick={()=>setView(v)}
              className={`px-2.5 py-1 rounded-lg text-xs font-medium border transition-all ${view===v?'bg-amber-500 text-white border-amber-500':'bg-white text-gray-600 border-gray-200 hover:border-amber-300'}`}>
              {l}
            </button>
          ))}
        </div>
      </div>
      <div className="grid grid-cols-2 sm:grid-cols-4 gap-3 mb-4">
        <KPI label="SM MATRIZ — Qtd" value={stats.diaQtd} color="text-blue-700" bg="bg-blue-50" border="border-blue-100" sub="Operações Matriz"/>
        <KPI label="SM MATRIZ — Lib" value={stats.diaLib} color="text-blue-500" bg="bg-blue-50" border="border-blue-100" sub={`${stats.diaQtd?((stats.diaLib/stats.diaQtd)*100).toFixed(1):0}% do total`}/>
        <KPI label="SM FILIAL — Qtd" value={stats.filQtd} color="text-amber-700" bg="bg-amber-50" border="border-amber-100" sub="Operações Filial"/>
        <KPI label="SM FILIAL — Lib" value={stats.filLib} color="text-amber-500" bg="bg-amber-50" border="border-amber-100" sub={`${stats.filQtd?((stats.filLib/stats.filQtd)*100).toFixed(1):0}% do total`}/>
      </div>
      <div className="bg-white rounded-xl p-4 border border-gray-200 shadow-sm mb-4">
        <h3 className="text-xs text-gray-500 font-semibold mb-3 uppercase tracking-wide">Comparativo diário — {ymLabel(selMonth)}</h3>
        <ResponsiveContainer width="100%" height={280}>
          <ComposedChart data={chartData} margin={{top:4,right:8,left:-10,bottom:0}}>
            <CartesianGrid strokeDasharray="3 3" stroke="#f0f0f0"/>
            <XAxis dataKey="label" tick={{fill:"#9ca3af",fontSize:9}} angle={-45} textAnchor="end" height={40}/>
            <YAxis tick={{fill:"#9ca3af",fontSize:10}}/>
            <Tooltip content={<TTip/>}/>
            <Legend wrapperStyle={{fontSize:11,paddingTop:6}}/>
            {showQ && <Bar dataKey="diaQtd" name="SM MATRIZ — Qtd" fill="#2563eb" radius={[3,3,0,0]} maxBarSize={12}/>}
            {showL && <Bar dataKey="diaLib" name="SM MATRIZ — Lib" fill="#93c5fd" radius={[3,3,0,0]} maxBarSize={12}/>}
            {showQ && <Line dataKey="filQtd" name="SM FILIAL — Qtd" stroke="#d97706" strokeWidth={2} dot={{r:2}} connectNulls/>}
            {showL && <Line dataKey="filLib" name="SM FILIAL — Lib" stroke="#fbbf24" strokeWidth={2} strokeDasharray="4 2" dot={{r:2}} connectNulls/>}
          </ComposedChart>
        </ResponsiveContainer>
      </div>
      <div className="bg-white rounded-xl border border-gray-200 shadow-sm overflow-auto max-h-64">
        <div className="px-4 py-2 border-b border-gray-100 text-xs font-semibold text-gray-600 uppercase tracking-wide bg-gray-50">Tabela — {ymLabel(selMonth)}</div>
        <table className="w-full text-xs">
          <thead><tr className="text-gray-400 border-b border-gray-100 bg-gray-50">
            <th className="text-left px-4 py-2">Data</th>
            <th className="text-center px-3 py-2 text-blue-600">MAT Qtd</th>
            <th className="text-center px-3 py-2 text-blue-400">MAT Lib</th>
            <th className="text-center px-3 py-2 text-amber-600">FIL Qtd</th>
            <th className="text-center px-3 py-2 text-amber-400">FIL Lib</th>
            <th className="text-center px-3 py-2 text-gray-400">Δ</th>
          </tr></thead>
          <tbody>{chartData.filter(r=>r.diaQtd!==null||r.filQtd!==null).map((r,i)=>{
            const delta=(Number(r.diaQtd)||0)-(Number(r.filQtd)||0);
            return <tr key={i} className="border-b border-gray-50 hover:bg-gray-50">
              <td className="px-4 py-1.5 text-gray-700 font-mono">{r.label}</td>
              <td className="text-center px-3 py-1.5 text-blue-700 font-semibold">{r.diaQtd??'—'}</td>
              <td className="text-center px-3 py-1.5 text-blue-500">{r.diaLib??'—'}</td>
              <td className="text-center px-3 py-1.5 text-amber-700 font-semibold">{r.filQtd??'—'}</td>
              <td className="text-center px-3 py-1.5 text-amber-500">{r.filLib??'—'}</td>
              <td className={`text-center px-3 py-1.5 font-semibold ${delta>0?'text-green-600':delta<0?'text-red-500':'text-gray-400'}`}>{delta>0?`+${delta}`:delta}</td>
            </tr>;
          })}</tbody>
        </table>
      </div>
    </div>
  );
}

